// Generar los próximos 5 días hábiles
const diasHabiles = [];
const hoy = new Date();
let i = 0;
while (diasHabiles.length < 5) {
  i++;
  const d = new Date(hoy);
  d.setDate(hoy.getDate() + i);
  const dow = d.getDay();
  if (dow !== 0 && dow !== 6) { // Excluir sábado y domingo
    const dd = String(d.getDate()).padStart(2, '0');
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const yyyy = d.getFullYear();
    diasHabiles.push({ label: `${dd}/${mm}/${yyyy}`, code: String(diasHabiles.length + 1) });
  }
}

const response = [
  `📅 *Sistema de Turnos*`,
  ``,
  `Seleccioná la *fecha* de tu turno:`,
  ``,
  ...diasHabiles.map(d => `${d.code}️⃣  ${d.label}`),
  ``,
  `Respondé con el *número* de la fecha que preferís.`,
  ``,
  `🕐 Horarios disponibles: *Lun a Vie 8:00 a 17:00hs*`
].join('\n');

// Guardar fechas disponibles en sesión
session.data.diasHabiles = diasHabiles;
staticData.sessions = { ...sessions, [phone]: session };

return [{ json: { phone, response } }];

